class LCG:
 def __init__(self, seed, a, c, m):
 self.state = seed
 self.a = a
 self.c = c
 self.m = m

 def next(self):
 self.state = (self.a * self.state + self.c) % self.m
 return self.state

 def next_float(self):
 return self.next() / self.m

# Example: Park-Miller minimal standard
lcg = LCG(seed=1, a=16807, c=0, m=2147483647)
for i in range(10):
 print(lcg.next())

import math

def prime_factors(n):
 factors = []
 d = 2
 while d * d <= n:
 while n % d == 0:
 factors.append(d)
 n //= d
 d += 1
 if n > 1:
 factors.append(n)
 return factors

def hull_dobell_full_period(a, c, m):
 # Condition 1: gcd(c, m) = 1
 if math.gcd(c, m) != 1:
 return False, "gcd(c,m) ≠ 1"

 # Condition 2: prime factors of m divide (a-1)
 factors = prime_factors(m)
 for p in factors:
 if (a - 1) % p != 0:
 return False, f"p={p} does not divide (a-1)"

 # Condition 3: if 4|m then 4|(a-1)
 if m % 4 == 0 and (a - 1) % 4 != 0:
 return False, "4|m but 4 ∤ (a-1)"

 return True, "Full period achievable"

# Test with m=31, a=3, c=1
print(hull_dobell_full_period(3, 1, 31))
